/** @internal */
export interface TooltipStateProps {
    /**
     * Delay time it takes to show the tooltip.
     */
    delay?: number;
    /** Defines if the tooltip should be open initially when used uncontrolled.
     * @defaultValue false
     */
    defaultOpen?: boolean;
    /**
     * Defines if the tooltip is open / closed in a controlled component. If
     * you bind open, you will need to react to `onOpenChange` yourself in order
     * to open and close the tooltip.
     */
    open?: boolean;
    /** onOpenChange fired when the tooltip would open. */
    onOpenChange?: (isOpen: boolean) => void;
}
/**
 * @internal
 * Controls the state of a tooltip considering global warmup and cooldown timeouts
 */
export declare function useTooltipState(props: TooltipStateProps): {
    isOpen: boolean;
    open: (immediate?: boolean) => void;
    close: () => void;
};
